// pages/employer/EmployerMessages.jsx
import React, { useState, useRef, useEffect } from 'react';
import { useMessaging } from '../../MessagingContext';
import './Messages.css';

function timeLabel(iso) {
  const d = new Date(iso);
  return d.toLocaleTimeString('en-IN', { hour: '2-digit', minute: '2-digit' });
}
function dateLabel(iso) {
  return new Date(iso).toLocaleDateString('en-IN', { day: 'numeric', month: 'short' });
}

export default function EmployerMessages() {
  const { threads, sendMessage, markThreadRead } = useMessaging();
  const [activeId, setActiveId] = useState(threads[0]?.id || null);
  const [input, setInput]       = useState('');
  const [search, setSearch]     = useState('');
  const bottomRef = useRef(null);

  const activeThread = threads.find(t => t.id === activeId);
  const filtered = threads.filter(t =>
    t.applicantName.toLowerCase().includes(search.toLowerCase()) ||
    t.internshipRole.toLowerCase().includes(search.toLowerCase())
  );

  useEffect(() => {
    if (activeId) markThreadRead(activeId);
  }, [activeId]);

  useEffect(() => {
    bottomRef.current?.scrollIntoView({ behavior: 'smooth' });
  }, [activeThread?.messages?.length]);

  const handleSend = () => {
    if (!input.trim() || !activeId) return;
    sendMessage(activeId, input.trim(), 'employer');
    setInput('');
  };

  return (
    <div className="msg-page page-enter">
      <div className="msg-page__header">
        <div className="section-label">Employer</div>
        <h1 className="msg-page__title">Messages</h1>
      </div>

      <div className="msg-layout">
        {/* THREAD LIST */}
        <aside className="msg-sidebar">
          <div className="msg-sidebar__search-wrap">
            <span className="msg-sidebar__search-icon">🔍</span>
            <input
              className="msg-sidebar__search"
              placeholder="Search conversations..."
              value={search}
              onChange={e => setSearch(e.target.value)}
            />
          </div>
          <div className="msg-sidebar__list">
            {filtered.length === 0 && (
              <div className="msg-sidebar__empty">No conversations found.</div>
            )}
            {filtered.map(t => (
              <div
                key={t.id}
                className={`msg-thread ${activeId === t.id ? 'msg-thread--active' : ''} ${t.unread > 0 ? 'msg-thread--unread' : ''}`}
                onClick={() => setActiveId(t.id)}
              >
                <div className="msg-thread__avatar" style={{ '--av': t.applicantColor }}>
                  {t.applicantInitials}
                </div>
                <div className="msg-thread__info">
                  <div className="msg-thread__top">
                    <span className="msg-thread__name">{t.applicantName}</span>
                    <span className="msg-thread__time">{dateLabel(t.lastTime)}</span>
                  </div>
                  <span className="msg-thread__role">{t.internshipRole}</span>
                  <span className="msg-thread__preview">{t.lastMessage}</span>
                </div>
                {t.unread > 0 && (
                  <span className="msg-thread__badge">{t.unread}</span>
                )}
              </div>
            ))}
          </div>
        </aside>

        {/* CHAT PANEL */}
        {activeThread ? (
          <div className="msg-chat">
            <div className="msg-chat__header">
              <div className="msg-chat__header-avatar" style={{ '--av': activeThread.applicantColor }}>
                {activeThread.applicantInitials}
              </div>
              <div className="msg-chat__header-info">
                <p className="msg-chat__header-name">{activeThread.applicantName}</p>
                <p className="msg-chat__header-role">{activeThread.internshipRole}</p>
              </div>
              <div className="msg-chat__header-actions">
                <a href="#" className="btn btn-secondary btn-sm">📄 View Profile</a>
              </div>
            </div>

            <div className="msg-chat__body">
              {activeThread.messages.map((m, i) => {
                const isEmployer = m.from === 'employer';
                return (
                  <div key={m.id} className={`msg-bubble-wrap ${isEmployer ? 'msg-bubble-wrap--right' : ''}`}>
                    {!isEmployer && (
                      <div className="msg-bubble__avatar" style={{ '--av': activeThread.applicantColor }}>
                        {activeThread.applicantInitials}
                      </div>
                    )}
                    <div className={`msg-bubble ${isEmployer ? 'msg-bubble--employer' : 'msg-bubble--applicant'}`}>
                      <p>{m.text}</p>
                      <span className="msg-bubble__time">{timeLabel(m.time)}</span>
                    </div>
                  </div>
                );
              })}
              <div ref={bottomRef} />
            </div>

            <div className="msg-chat__footer">
              <input
                className="msg-chat__input"
                placeholder="Type a message..."
                value={input}
                onChange={e => setInput(e.target.value)}
                onKeyDown={e => { if (e.key === 'Enter' && !e.shiftKey) { e.preventDefault(); handleSend(); }}}
              />
              <button
                className={`msg-chat__send ${input.trim() ? 'msg-chat__send--active' : ''}`}
                onClick={handleSend}
                disabled={!input.trim()}
              >
                ➤
              </button>
            </div>
          </div>
        ) : (
          <div className="msg-chat msg-chat--empty">
            <span>💬</span>
            <p>Select a conversation to start messaging</p>
          </div>
        )}
      </div>
    </div>
  );
}
